-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("位置覆盖 ")
local SpotRight = Tabs.Spot:AddRightGroupbox("快速保存键 ")

local overrideLabel = SpotLeft:AddLabel({ Text = "自定义位置：关闭 " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "已保存：无 " })

SpotLeft:AddButton("保存当前位置 ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="错误 ", Description="没有角色！ ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="错误 ", Description="没有 HumanoidRootPart！ ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="位置已保存！ ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("清除自定义位置 ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("已保存：无 ")
    Library:Notify({Title="已清除 ", Description="使用原先捕获的位置。 ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "快速保存键：F " })

SpotRight:AddButton("设置快速保存键 ", function()
    M.setSettingKeybind(true)
    keybindLabel:SetText("现在按下一个键... ")
    Library:Notify({Title="按任意键 ", Description="该按键将保存你的位置。 ", Duration=4})
end)

SpotRight:AddButton("清除快速保存键 ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("快速保存键：无 ")
    Library:Notify({Title="按键已清除 ", Description="未设置快速保存键。 ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

