SpeedGroup:AddSlider("WalkSpeedSlider", {
    Text     = "移动速度 ",
    Default  = 16,
    Min      = 0,
    Max      = 710,
    Suffix   = " studs/s",
    Rounding = 0,
    Callback = function(val)
        M.walkSpeed = val
        if not M.speedLoopEnabled then
            M.speedLoopEnabled = true
            task.spawn(M.speedLoop)
        end
    end,
})

SpeedGroup:AddDivider()

SpeedGroup:AddButton("将速度重置为16 ", function()
    M.speedLoopEnabled = false
    task.wait(0.1)
    local char = game.Players.LocalPlayer.Character
    if char then
        local hum = char:FindFirstChildOfClass("Humanoid")
        if hum then hum.WalkSpeed = 16 end
    end
    M.walkSpeed = 16
    if Library.Sliders and Library.Sliders.WalkSpeedSlider then
        Library.Sliders.WalkSpeedSlider:SetValue(16)
    end
    Library:Notify({Title="速度已重置 ", Description="恢复正常（16）。 ", Duration=3})
end)

